// ===== LOGO COMPONENT =====
function LogoASA({ size = 40 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <linearGradient id="logoGrad" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor="#a855f7"/>
          <stop offset="100%" stopColor="#ec4899"/>
        </linearGradient>
        <linearGradient id="bgGrad" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor="#1e1b4b"/>
          <stop offset="100%" stopColor="#2d1b4e"/>
        </linearGradient>
      </defs>
      {/* Hexagon background */}
      <path d="M50 5 L90 27.5 L90 72.5 L50 95 L10 72.5 L10 27.5 Z" fill="url(#bgGrad)" stroke="url(#logoGrad)" strokeWidth="2.5"/>
      {/* Letter A left */}
      <text x="15" y="66" fontFamily="Georgia, serif" fontSize="36" fontWeight="bold" fill="url(#logoGrad)">A</text>
      {/* Letter S center */}
      <text x="34" y="66" fontFamily="Georgia, serif" fontSize="36" fontWeight="bold" fill="white">S</text>
      {/* Letter A right */}
      <text x="56" y="66" fontFamily="Georgia, serif" fontSize="36" fontWeight="bold" fill="url(#logoGrad)">A</text>
      {/* Decorative line */}
      <line x1="22" y1="72" x2="78" y2="72" stroke="url(#logoGrad)" strokeWidth="1.5" strokeDasharray="3 2"/>
    </svg>
  );
}

